2	//!
3	//! Provides WASM to COR24 translation and full pipeline support.
4	//! Also provides MSP430 to COR24 translation for the 16-bit IR approach.
5	
6	mod pipeline;
7	pub mod msp430;
8	
9	pub use pipeline::{run_pipeline, print_leds};
10	pub use msp430::translate_msp430;
