15	/// Translate WASM binary to COR24 assembly
16	pub fn translate_wasm(wasm: &[u8]) -> Result<String> {
17	    let mut output = String::new();
18	    output.push_str("; COR24 Assembly - Generated by wasm2cor24\n");
19	    output.push_str("; From Rust source via WASM\n\n");
20	
21	    let mut types: Vec<FuncType> = Vec::new();
22	    let mut func_types: Vec<u32> = Vec::new();
23	    let mut exports: Vec<(String, u32)> = Vec::new();
24	
25	    // First pass: collect metadata
26	    for payload in Parser::new(0).parse_all(wasm) {
27	        match payload? {
28	            Payload::TypeSection(reader) => {
29	                for rec_group in reader {
30	                    let rec_group = rec_group?;
31	                    for ty in rec_group.into_types() {
32	                        if let wasmparser::CompositeType::Func(ft) = ty.composite_type {
33	                            types.push(ft);
34	                        }
35	                    }
36	                }
37	            }
38	            Payload::FunctionSection(reader) => {
39	                for func in reader {
40	                    func_types.push(func?);
41	                }
42	            }
43	            Payload::ExportSection(reader) => {
44	                for export in reader {
45	                    let export = export?;
46	                    if let wasmparser::ExternalKind::Func = export.kind {
47	                        exports.push((export.name.to_string(), export.index));
48	                    }
49	                }
50	            }
51	            _ => {}
52	        }
53	    }
54	
55	    // Second pass: translate code
56	    let mut func_index = 0;
57	    for payload in Parser::new(0).parse_all(wasm) {
58	        if let Payload::CodeSectionEntry(body) = payload? {
59	            let type_idx = func_types.get(func_index).copied().unwrap_or(0) as usize;
60	            let func_type = types.get(type_idx);
61	
62	            let func_name = exports
63	                .iter()
64	                .find(|(_, idx)| *idx == func_index as u32)
65	                .map(|(name, _)| name.clone())
66	                .unwrap_or_else(|| format!("func_{}", func_index));
67	
68	            output.push_str(&translate_function(&func_name, func_type, body)?);
69	            func_index += 1;
70	        }
71	    }
72	
73	    Ok(output)
74	}
