1	//! wasm2cor24 - Translate WASM to COR24 assembly
2	//!
3	//! Minimal prototype supporting basic integer operations.
4	
5	use anyhow::Result;
6	use std::env;
7	use std::fs;
8	use wasmparser::{FuncType, Operator, Parser, Payload};
9	
10	fn main() -> Result<()> {
11	    let args: Vec<String> = env::args().collect();
12	
13	    if args.len() < 2 {
14	        eprintln!("Usage: wasm2cor24 <input.wasm> [-o output.s]");
15	        eprintln!("       wasm2cor24 --test   # Run built-in test");
16	        std::process::exit(1);
17	    }
18	
19	    if args[1] == "--test" {
20	        return run_test();
21	    }
22	
23	    let input_path = &args[1];
24	    let output_path = if args.len() >= 4 && args[2] == "-o" {
25	        Some(args[3].clone())
26	    } else {
27	        None
28	    };
29	
30	    let wasm_bytes = fs::read(input_path)?;
31	    let asm = translate_wasm(&wasm_bytes)?;
32	
33	    if let Some(path) = output_path {
34	        fs::write(&path, &asm)?;
35	        println!("Wrote COR24 assembly to {}", path);
36	    } else {
37	        println!("{}", asm);
38	    }
39	
40	    Ok(())
41	}
42	
43	/// Run built-in test with inline WASM
44	fn run_test() -> Result<()> {
45	    println!("=== wasm2cor24 Test ===\n");
46	
47	    // Minimal WASM module: (func (export "add") (param i32 i32) (result i32) local.get 0 local.get 1 i32.add)
48	    // Hand-assembled WASM binary
49	    let wasm_add: &[u8] = &[
50	        0x00, 0x61, 0x73, 0x6D, // magic: \0asm
51	        0x01, 0x00, 0x00, 0x00, // version: 1
52	        // Type section
53	        0x01, 0x07, // section id=1, size=7
54	        0x01, // 1 type
55	        0x60, 0x02, 0x7F, 0x7F, 0x01, 0x7F, // func (i32, i32) -> i32
56	        // Function section
57	        0x03, 0x02, // section id=3, size=2
58	        0x01, 0x00, // 1 function, type index 0
59	        // Export section
60	        0x07, 0x07, // section id=7, size=7
61	        0x01, // 1 export
62	        0x03, 0x61, 0x64, 0x64, // "add"
63	        0x00, 0x00, // func, index 0
64	        // Code section
65	        0x0A, 0x09, // section id=10, size=9
66	        0x01, // 1 function body
67	        0x07, // body size=7
68	        0x00, // 0 locals
69	        0x20, 0x00, // local.get 0
70	        0x20, 0x01, // local.get 1
71	        0x6A, // i32.add
72	        0x0B, // end
73	    ];
74	
