130	/// Translate WASM binary to COR24 assembly
131	fn translate_wasm(wasm: &[u8]) -> Result<String> {
132	    let mut output = String::new();
133	    output.push_str("; COR24 Assembly - Generated by wasm2cor24\n");
134	    output.push_str("; Supports: i32.add, i32.sub, i32.and, i32.or, i32.xor\n");
135	    output.push_str(";           i32.const, local.get, local.set\n\n");
136	
137	    let mut types: Vec<FuncType> = Vec::new();
138	    let mut func_types: Vec<u32> = Vec::new();
139	    let mut exports: Vec<(String, u32)> = Vec::new();
140	
141	    // First pass: collect metadata
142	    for payload in Parser::new(0).parse_all(wasm) {
143	        match payload? {
144	            Payload::TypeSection(reader) => {
145	                for rec_group in reader {
146	                    let rec_group = rec_group?;
147	                    for ty in rec_group.into_types() {
148	                        if let wasmparser::CompositeType::Func(ft) = ty.composite_type {
149	                            types.push(ft);
150	                        }
151	                    }
152	                }
153	            }
154	            Payload::FunctionSection(reader) => {
155	                for func in reader {
156	                    func_types.push(func?);
157	                }
158	            }
159	            Payload::ExportSection(reader) => {
160	                for export in reader {
161	                    let export = export?;
162	                    if let wasmparser::ExternalKind::Func = export.kind {
163	                        exports.push((export.name.to_string(), export.index));
164	                    }
165	                }
166	            }
167	            _ => {}
168	        }
169	    }
170	
171	    // Second pass: translate code
172	    let mut func_index = 0;
173	    for payload in Parser::new(0).parse_all(wasm) {
174	        if let Payload::CodeSectionEntry(body) = payload? {
175	            let type_idx = func_types.get(func_index).copied().unwrap_or(0) as usize;
176	            let func_type = types.get(type_idx);
177	
178	            // Find export name for this function
179	            let func_name = exports
180	                .iter()
181	                .find(|(_, idx)| *idx == func_index as u32)
182	                .map(|(name, _)| name.clone())
183	                .unwrap_or_else(|| format!("func_{}", func_index));
184	
185	            output.push_str(&translate_function(&func_name, func_type, body)?);
186	            func_index += 1;
187	        }
188	    }
189	
190	    Ok(output)
191	}
192	
193	/// Translate a single WASM function to COR24 assembly
194	fn translate_function(
195	    name: &str,
196	    func_type: Option<&FuncType>,
197	    body: wasmparser::FunctionBody,
198	) -> Result<String> {
199	    let debug = std::env::var("WASM_DEBUG").is_ok();
200	    let mut output = String::new();
201	
202	    // Function header
203	    output.push_str(&format!("; Function: {}\n", name));
204	    if let Some(ft) = func_type {
205	        output.push_str(&format!(
206	            "; Signature: ({}) -> {}\n",
207	            ft.params()
208	                .iter()
209	                .map(|t| format!("{:?}", t))
210	                .collect::<Vec<_>>()
211	                .join(", "),
212	            if ft.results().is_empty() {
213	                "void".to_string()
214	            } else {
215	                ft.results()
216	                    .iter()
217	                    .map(|t| format!("{:?}", t))
218	                    .collect::<Vec<_>>()
219	                    .join(", ")
220	            }
221	        ));
222	    }
223	    output.push_str(&format!("{}:\n", name));
224	
225	    // Parse locals
226	    let mut locals_reader = body.get_locals_reader()?;
227	    let mut num_locals: u32 = 0;
228	
229	    for _ in 0..locals_reader.get_count() {
230	        let (count, _ty) = locals_reader.read()?;
231	        num_locals += count;
232	    }
233	
234	    // Get parameter count from function type
235	    let num_params = func_type.map(|ft| ft.params().len() as u32).unwrap_or(0);
236	    let total_locals = num_params + num_locals;
237	
238	    // Always use prologue for stack-based locals (simpler, avoids register conflicts)
239	    output.push_str("        push    fp\n");
240	    output.push_str("        mov     fp, sp\n");
241	    if total_locals > 0 {
242	        output.push_str(&format!(
243	            "        add     sp, -{}\n",
244	            total_locals * 3
245	        )); // 3 bytes per local
246	        // Initialize locals to 0 (params would be passed in registers, copy to stack)
247	        for i in 0..num_params {
248	            // Copy parameters from r0, r1, ... to stack frame
249	            let offset = i * 3;
250	            output.push_str(&format!("        sw      r{}, {}(fp)\n", i, offset));
251	        }
252	    }
253	
254	    // Track virtual stack (WASM is stack-based)
255	    let mut stack_depth: i32 = 0;
256	    let mut code = Vec::new();
257	
258	    // Track labels for control flow
259	    let mut label_counter = 0;
260	    let mut block_stack: Vec<(String, String)> = Vec::new(); // (start_label, end_label)
261	
262	    // Parse operators
263	    let ops_reader = body.get_operators_reader()?;
264	    for op in ops_reader {
265	        let op = op?;
266	        if debug {
267	            eprintln!("[WASM] stack={} op={:?}", stack_depth, op);
268	        }
269	        match op {
270	            Operator::LocalGet { local_index } => {
271	                // All locals are on the stack frame - load to expression register
272	                let offset = local_index * 3;
273	                code.push(format!("        lw      r{}, {}(fp)\n", stack_depth, offset));
274	                stack_depth += 1;
275	            }
276	
277	            Operator::LocalSet { local_index } => {
278	                // All locals are on the stack frame - store from expression register
279	                stack_depth -= 1;
280	                let offset = local_index * 3;
281	                code.push(format!("        sw      r{}, {}(fp)\n", stack_depth, offset));
282	            }
283	
284	            Operator::I32Const { value } => {
285	                if (-128..=127).contains(&value) {
286	                    code.push(format!("        lc      r{}, {}\n", stack_depth, value));
287	                } else {
288	                    code.push(format!(
289	                        "        la      r{}, 0x{:06X}\n",
290	                        stack_depth,
291	                        value as u32 & 0xFFFFFF
292	                    ));
293	                }
294	                stack_depth += 1;
295	            }
296	
297	            Operator::I32Add => {
298	                stack_depth -= 1;
299	                code.push(format!(
300	                    "        add     r{}, r{}\n",
301	                    stack_depth - 1,
302	                    stack_depth
303	                ));
304	            }
305	
306	            Operator::I32Sub => {
307	                stack_depth -= 1;
308	                code.push(format!(
309	                    "        sub     r{}, r{}\n",
310	                    stack_depth - 1,
311	                    stack_depth
312	                ));
313	            }
314	
315	            Operator::I32And => {
316	                stack_depth -= 1;
317	                code.push(format!(
318	                    "        and     r{}, r{}\n",
319	                    stack_depth - 1,
320	                    stack_depth
321	                ));
322	            }
323	
324	            Operator::I32Or => {
325	                stack_depth -= 1;
326	                code.push(format!(
327	                    "        or      r{}, r{}\n",
328	                    stack_depth - 1,
329	                    stack_depth
330	                ));
331	            }
332	
333	            Operator::I32Xor => {
334	                stack_depth -= 1;
335	                code.push(format!(
336	                    "        xor     r{}, r{}\n",
337	                    stack_depth - 1,
338	                    stack_depth
339	                ));
340	            }
341	
342	            Operator::I32Shl => {
343	                stack_depth -= 1;
344	                code.push(format!(
345	                    "        shl     r{}, r{}\n",
346	                    stack_depth - 1,
347	                    stack_depth
348	                ));
349	            }
350	
351	            Operator::I32ShrU => {
352	                stack_depth -= 1;
353	                code.push(format!(
354	                    "        srl     r{}, r{}\n",
355	                    stack_depth - 1,
356	                    stack_depth
357	                ));
358	            }
359	
360	            Operator::I32ShrS => {
361	                stack_depth -= 1;
362	                code.push(format!(
363	                    "        sra     r{}, r{}\n",
364	                    stack_depth - 1,
365	                    stack_depth
366	                ));
367	            }
368	
369	            Operator::I32Store8 { memarg } => {
370	                // Store byte: mem[addr + offset] = value
371	                // Stack: [addr, value] -> []
372	                stack_depth -= 2;
373	                let addr_reg = stack_depth;
374	                let val_reg = stack_depth + 1;
375	                if memarg.offset > 0 {
376	                    code.push(format!(
377	                        "        la      r{}, 0x{:06X}\n",
378	                        val_reg + 1,
379	                        memarg.offset as u32 & 0xFFFFFF
380	                    ));
381	                    code.push(format!("        add     r{}, r{}\n", addr_reg, val_reg + 1));
382	                }
383	                code.push(format!("        sb      r{}, 0(r{})\n", val_reg, addr_reg));
384	            }
385	
386	            Operator::I32Load8U { memarg } => {
387	                // Load unsigned byte: value = mem[addr + offset]
388	                // Stack: [addr] -> [value]
389	                let addr_reg = stack_depth - 1;
390	                if memarg.offset > 0 {
391	                    code.push(format!(
392	                        "        la      r{}, 0x{:06X}\n",
393	                        addr_reg + 1,
394	                        memarg.offset as u32 & 0xFFFFFF
395	                    ));
396	                    code.push(format!("        add     r{}, r{}\n", addr_reg, addr_reg + 1));
397	                }
398	                code.push(format!("        lbu     r{}, 0(r{})\n", addr_reg, addr_reg));
399	            }
400	
401	            Operator::Loop { .. } => {
402	                let start_label = format!(".L{}", label_counter);
403	                let end_label = format!(".L{}", label_counter + 1);
404	                label_counter += 2;
405	                block_stack.push((start_label.clone(), end_label.clone()));
406	                code.push(format!("{}:\n", start_label));
407	            }
408	
409	            Operator::Block { .. } => {
410	                let start_label = format!(".L{}", label_counter);
411	                let end_label = format!(".L{}", label_counter + 1);
412	                label_counter += 2;
413	                block_stack.push((start_label, end_label.clone()));
414	            }
415	
416	            Operator::Br { relative_depth } => {
417	                // Branch to enclosing block
418	                if let Some((start, _end)) = block_stack.iter().rev().nth(relative_depth as usize) {
419	                    code.push(format!("        bra     {}\n", start));
420	                }
421	            }
422	
423	            Operator::BrIf { relative_depth } => {
424	                // Conditional branch: if top of stack != 0, branch
425	                stack_depth -= 1;
426	                if let Some((start, _end)) = block_stack.iter().rev().nth(relative_depth as usize) {
427	                    code.push(format!("        ceq     r{}, z\n", stack_depth));
428	                    code.push(format!("        brf     {}\n", start)); // branch if NOT equal to zero
429	                }
430	            }
431	
432	            Operator::I32LtU => {
433	                // Unsigned less than: C = (a < b)
434	                stack_depth -= 1;
435	                code.push(format!(
436	                    "        clu     r{}, r{}\n",
437	                    stack_depth - 1,
438	                    stack_depth
439	                ));
440	                // Result is in C flag, but WASM expects i32 on stack
441	                code.push(format!("        mov     r{}, c\n", stack_depth - 1));
442	            }
443	
444	            Operator::I32LtS => {
445	                // Signed less than
446	                stack_depth -= 1;
447	                code.push(format!(
448	                    "        cls     r{}, r{}\n",
449	                    stack_depth - 1,
450	                    stack_depth
451	                ));
452	                code.push(format!("        mov     r{}, c\n", stack_depth - 1));
453	            }
454	
455	            Operator::I32Eqz => {
456	                // Test if zero: result = (value == 0) ? 1 : 0
457	                code.push(format!("        ceq     r{}, z\n", stack_depth - 1));
458	                code.push(format!("        mov     r{}, c\n", stack_depth - 1));
459	            }
460	
461	            Operator::I32Eq => {
462	                // Equality test
463	                stack_depth -= 1;
464	                code.push(format!(
465	                    "        ceq     r{}, r{}\n",
466	                    stack_depth - 1,
467	                    stack_depth
468	                ));
469	                code.push(format!("        mov     r{}, c\n", stack_depth - 1));
470	            }
471	
472	            Operator::End => {
473	                // End of block or function
474	                if let Some((_start, end)) = block_stack.pop() {
475	                    code.push(format!("{}:\n", end));
476	                }
477	            }
478	
479	            Operator::Return => {
480	                // Early return
481	                code.push("        mov     sp, fp\n".to_string());
482	                code.push("        pop     fp\n".to_string());
483	                code.push("        jmp     (r1)\n".to_string());
484	            }
485	
486	            Operator::Drop => {
487	                // Discard top of stack
488	                stack_depth -= 1;
489	            }
490	
491	            Operator::LocalTee { local_index } => {
492	                // Set local but keep value on stack
493	                let src_reg = stack_depth - 1;
494	                let offset = local_index * 3;
495	                code.push(format!("        sw      r{}, {}(fp)\n", src_reg, offset));
496	            }
497	
498	            other => {
499	                code.push(format!("        ; TODO: {:?}\n", other));
500	            }
501	        }
502	    }
503	
504	    // Add generated code
505	    for line in code {
506	        output.push_str(&line);
507	    }
508	
509	    // Epilogue (always, since we always have prologue)
510	    output.push_str("        mov     sp, fp\n");
511	    output.push_str("        pop     fp\n");
512	
513	    // Return - result is in r0
514	    output.push_str("        halt                ; return (use jmp (r1) for real calls)\n");
515	    output.push('\n');
516	
517	    Ok(output)
518	}
