1	//! msp430-to-cor24 CLI
2	//!
3	//! Translates MSP430 assembly (from rustc) to COR24 assembly.
4	//!
5	//! Usage:
6	//!   msp430-to-cor24 <input.s> [-o output.s]
7	//!   msp430-to-cor24 --test           # translate built-in test case
8	//!   msp430-to-cor24 --compile <dir>  # compile Rust project, translate, assemble
9	
10	use anyhow::Result;
11	use std::env;
12	use std::fs;
13	
14	fn main() -> Result<()> {
15	    let args: Vec<String> = env::args().collect();
16	
17	    // Parse named flags from anywhere in args
18	    let mut entry_point: Option<String> = None;
19	    let mut output_path: Option<String> = None;
20	    let mut positional: Vec<String> = Vec::new();
21	
22	    let mut i = 1;
23	    while i < args.len() {
24	        match args[i].as_str() {
25	            "--entry" | "-e" => {
26	                i += 1;
27	                entry_point = args.get(i).cloned();
28	            }
29	            "-o" => {
30	                i += 1;
31	                output_path = args.get(i).cloned();
32	            }
33	            _ => positional.push(args[i].clone()),
34	        }
35	        i += 1;
36	    }
37	
38	    let cmd = positional.first().map(|s| s.as_str()).unwrap_or("");
39	
40	    match cmd {
41	        "--test" => run_test(),
42	        "--compile" => {
43	            let dir = positional.get(1).map(|s| s.as_str()).unwrap_or(".");
44	            compile_and_translate(dir, entry_point.as_deref().unwrap_or("start"))
45	        }
46	        "" => {
47	            eprintln!("Usage: msp430-to-cor24 <input.s> [-o output.s] [--entry <func>]");
48	            eprintln!("       msp430-to-cor24 --test");
49	            eprintln!("       msp430-to-cor24 --compile <rust-project-dir> [--entry <func>]");
50	            std::process::exit(1);
51	        }
52	        input_path => {
53	            let msp430_asm = fs::read_to_string(input_path)?;
54	            let entry = entry_point.as_deref().unwrap_or("start");
55	            let cor24_asm = wasm2cor24::translate_msp430(&msp430_asm, entry)?;
56	
57	            if let Some(out_path) = output_path {
58	                fs::write(&out_path, &cor24_asm)?;
59	                eprintln!("Wrote COR24 assembly to {}", out_path);
60	            } else {
61	                println!("{}", cor24_asm);
62	            }
63	
64	            Ok(())
65	        }
66	    }
67	}
68	
69	fn run_test() -> Result<()> {
70	    // The MSP430 assembly from our test compilation
71	    let msp430_asm = r#"
72		.file	"msp430_test.93892fd9a69df810-cgu.0"
73		.section	.text.add,"ax",@progbits
74		.globl	add
75		.p2align	1
76		.type	add,@function
77	add:
78		add	r13, r12
79		ret
80	.Lfunc_end1:
81		.size	add, .Lfunc_end1-add
82	
83		.section	.text.bitmask,"ax",@progbits
84		.globl	bitmask
85		.p2align	1
86		.type	bitmask,@function
87	bitmask:
88		and	r13, r12
89		ret
90	.Lfunc_end2:
91		.size	bitmask, .Lfunc_end2-bitmask
92	
93		.section	.text.delay,"ax",@progbits
94		.globl	delay
95		.p2align	1
96		.type	delay,@function
97	delay:
98		sub	#2, r1
99		tst	r12
100		jeq	.LBB5_3
101		add	#-1, r12
102	.LBB5_2:
103		mov	r12, 0(r1)
104		add	#-1, r12
105		cmp	#-1, r12
106		jne	.LBB5_2
107	.LBB5_3:
108		add	#2, r1
109		ret
110	.Lfunc_end5:
111		.size	delay, .Lfunc_end5-delay
112	
113		.section	.text.mmio_read,"ax",@progbits
114		.globl	mmio_read
115		.p2align	1
116		.type	mmio_read,@function
117	mmio_read:
118		mov	0(r12), r12
119		ret
120	.Lfunc_end6:
121		.size	mmio_read, .Lfunc_end6-mmio_read
122	
123		.section	.text.mmio_write,"ax",@progbits
124		.globl	mmio_write
125		.p2align	1
126		.type	mmio_write,@function
127	mmio_write:
128		mov	r13, 0(r12)
129		ret
130	.Lfunc_end7:
131		.size	mmio_write, .Lfunc_end7-mmio_write
132	
133		.section	.text.blink_loop,"ax",@progbits
134		.globl	blink_loop
135		.p2align	1
136		.type	blink_loop,@function
137	blink_loop:
138	.LBB2_1:
139		mov	#-256, r12
140		mov	#1, r13
141		call	#mmio_write
142		mov	#1000, r12
143		call	#delay
144		mov	#-256, r12
145		clr	r13
146		call	#mmio_write
147		mov	#1000, r12
148		call	#delay
