//! cor24-run: COR24 assembler and emulator CLI
//!
//! Usage:
//!   cor24-run --demo                              Run built-in LED demo
//!   cor24-run --demo --speed 50000 --time 10      Run at 50k IPS for 10 seconds
//!   cor24-run --run <file.s>                      Assemble and run
//!   cor24-run --assemble <in.s> <out.bin> <out.lst>  Assemble to binary + listing

use cor24_emulator::assembler::Assembler;
use cor24_emulator::emulator::EmulatorCore;
use std::collections::VecDeque;
use std::env;
use std::fs;
use std::io::Write;
use std::thread;
use std::time::{Duration, Instant};

/// Default emulation speed (instructions per second)
const DEFAULT_SPEED: u64 = 100_000;

/// Default time limit in seconds
const DEFAULT_TIME_LIMIT: f64 = 10.0;

const COPYRIGHT: &str = "Copyright (c) 2026 Michael A Wright";
const LICENSE: &str = "MIT";
const REPOSITORY: &str = "https://github.com/sw-embed/cor24-rs";

fn print_version() {
    println!(
        "cor24-run {}\n{}\nLicense: {}\nRepository: {}\n\nBuild Information:\n  Host: {}\n  Commit: {}\n  Timestamp: {}",
        env!("CARGO_PKG_VERSION"),
        COPYRIGHT,
        LICENSE,
        REPOSITORY,
        env!("BUILD_HOST"),
        env!("GIT_HASH"),
        env!("BUILD_TIMESTAMP"),
    );
}

fn print_short_help() {
    println!("cor24-run: COR24 assembler and emulator\n");
    println!("Usage:");
    println!("  cor24-run --demo [options]        Run built-in LED demo");
    println!("  cor24-run --run <file.s> [opts]   Assemble and run");
    println!("  cor24-run --load-binary <f>@<a> --entry <a>  Run pre-assembled binaries");
    println!("  cor24-run --assemble <in.s> <out.bin> <out.lst>");
    println!();
    println!("Options:");
    println!("  -h                     Short help (this message)");

//! COR24 Assembler
//!
//! Parses COR24 assembly language and produces machine code.
//! Uses encoding tables extracted from the hardware decode ROM.
//!
//! COR24 is a C-Oriented RISC 24-bit architecture with:
//! - 3 general-purpose 24-bit registers (r0, r1, r2)
//! - 5 special registers: fp=r3, sp=r4, z=r5, iv=r6, ir=r7
//! - Single condition flag (C)
//! - Variable-length instructions (1, 2, or 4 bytes)
//! - 16MB address space (24-bit)
//! - Little-endian byte ordering

pub mod assembler;

// Re-export main types for convenience
pub use assembler::{AssembledLine, Assembler, AssemblyResult};

// Re-export emulator types that assembler consumers typically need
pub use cor24_emulator;

//! COR24 Assembly Emulator - Educational Programming Tool
//!
//! A COR24 emulator that teaches COR24 assembly programming through
//! interactive examples and challenges.
//!
//! COR24 is a C-Oriented RISC 24-bit architecture with:
