//! - 5 special registers: fp=r3, sp=r4, z=r5, iv=r6, ir=r7
//! - Single condition flag (C)
//! - Variable-length instructions (1, 2, or 4 bytes)
//! - 16MB address space (24-bit)
//! - Little-endian byte ordering

pub mod assembler;
pub mod challenge;
pub mod cpu;
pub mod emulator;
pub mod loader;

