fn print_leds(leds: u8) {
    print!("\rLEDs: ");
    for i in (0..8).rev() {
        if (leds >> i) & 1 == 0 { print!("\x1b[91m●\x1b[0m"); }  // active-low: 0=ON
        else { print!("○"); }
    }
    print!("  (0x{:02X})  ", leds);
    std::io::stdout().flush().ok();
}

/// Run emulator with timing, instruction limit, and queued UART input.
/// UART input bytes are fed one at a time after each batch, simulating
/// character-by-character typing at the emulated UART RX register.
fn run_with_timing(emu: &mut EmulatorCore, speed: u64, time_limit: f64, max_instructions: i64, uart_input: &[u8]) -> u64 {
    let start = Instant::now();
    let time_limit_duration = Duration::from_secs_f64(time_limit);

    let batch_size: u64 = if speed == 0 { 10000 } else { (speed / 100).max(1) };
    let batch_duration = if speed == 0 {
        Duration::ZERO
    } else {
        Duration::from_secs_f64(batch_size as f64 / speed as f64)
    };

    let mut total_instructions: u64 = 0;
    let mut batch_start = Instant::now();
    let mut prev_led = emu.get_led();
    let mut prev_uart_len = 0usize;
    let mut uart_input_pos = 0usize;

    emu.resume();

    loop {
        if start.elapsed() >= time_limit_duration {
            break;
        }

        if max_instructions >= 0 && total_instructions >= max_instructions as u64 {
            break;
        }

        let this_batch = if max_instructions >= 0 {
            let remaining = (max_instructions as u64).saturating_sub(total_instructions);
            batch_size.min(remaining).max(1)
        } else {
            batch_size
        };

        let result = emu.run_batch(this_batch);
        total_instructions += result.instructions_run;

        // Check for LED changes
        let led = emu.get_led();
        if led != prev_led {
            print_leds(led);
            prev_led = led;
        }

        // Print any new UART output
        let output = emu.get_uart_output();
        if output.len() > prev_uart_len {
            let new_chars = &output[prev_uart_len..];
            for ch in new_chars.chars() {
                if ch == '\n' {
                    println!("[UART TX @ {}] '\\n'", total_instructions);
                } else {
                    println!("[UART TX @ {}] '{}'  (0x{:02X})", total_instructions, ch, ch as u8);
                }
            }
            prev_uart_len = output.len();
        }

        // Feed next UART input character when previous was consumed (FIFO drain)
        // Only send when RX ready bit (bit 0 of status register) is clear,
        // meaning the program has read the previous byte.
        if uart_input_pos < uart_input.len() {
            let uart_status = emu.read_byte(0xFF0101);
            if uart_status & 0x01 == 0 {
                let ch = uart_input[uart_input_pos];
                emu.send_uart_byte(ch);
                if ch == b'!' {
                    println!("[UART RX] '!'  (0x21) — halt signal");
                } else if ch == b'\n' {
                    println!("[UART RX] '\\n'");
                } else {
                    println!("[UART RX] '{}'  (0x{:02X})", ch as char, ch);
                }
                uart_input_pos += 1;
            }
        }

        if result.instructions_run == 0 {
            break; // halted or paused
        }

        if speed > 0 {
            let elapsed = batch_start.elapsed();
            if elapsed < batch_duration {
                thread::sleep(batch_duration - elapsed);
            }
            batch_start = Instant::now();
        }
    }

    total_instructions
}

/// Load assembled bytes into emulator at their correct addresses
fn load_assembled(emu: &mut EmulatorCore, result: &cor24_emulator::assembler::AssemblyResult) {
    for line in &result.lines {
        if !line.bytes.is_empty() {
            for (i, &b) in line.bytes.iter().enumerate() {
                emu.write_byte(line.address + i as u32, b);
            }
        }
    }
}

/// LED counter demo with spin loop delay
const DEMO_SOURCE: &str = r#"
; LED Counter Demo with Spin Loop Delay
; Counts 0-255 on LEDs, loops forever

        push    fp
        mov     fp, sp
        add     sp, -3

        la      r1, -65536
        lc      r0, 0
        sw      r0, 0(fp)

main_loop:
        lw      r0, 0(fp)
        sb      r0, 0(r1)

        la      r2, 15000
delay:
        lc      r0, 1
        sub     r2, r0
        brt     delay

        lw      r0, 0(fp)
        lc      r2, 1
        add     r0, r2
        sw      r0, 0(fp)

        bra     main_loop
"#;

struct CliArgs {
    command: String,
    speed: u64,
    time_limit: f64,
    max_instructions: i64,
    file: Option<String>,
    dump: bool,
    entry: Option<String>,           // entry point label
    uart_input: Vec<u8>,             // characters to send to UART RX
    trace: usize,                    // number of trace entries to dump (0 = off)
    step: bool,                      // step mode: print each instruction
    uart_never_ready: bool,          // UART TX never becomes ready (test polling)
    terminal: bool,                  // bridge stdin/stdout to UART
    echo: bool,                      // echo stdin to stdout in terminal mode
    stack_kb: u32,                   // stack size in KB (3 or 8)
    load_binaries: Vec<(String, u32)>, // (file_path, load_address) pairs
    patches: Vec<(u32, u32)>,           // (address, 24-bit value) pairs
    base_addr: u32,                     // base address for assembly (--base-addr)
    switch_pressed: bool,               // button S2 state (--switch on)
}

/// Parse a numeric address string: 0x prefix, h suffix, or decimal.
fn parse_numeric_addr(s: &str) -> Option<u32> {
    if s.starts_with("0x") || s.starts_with("0X") {
        u32::from_str_radix(&s[2..], 16).ok()
    } else if s.ends_with('h') || s.ends_with('H') {
        u32::from_str_radix(&s[..s.len()-1], 16).ok()
    } else {
        s.parse::<u32>().ok()
    }
}

fn parse_args() -> CliArgs {
    let args: Vec<String> = env::args().collect();
    let mut cli = CliArgs {
        command: String::new(),
        speed: DEFAULT_SPEED,
        time_limit: DEFAULT_TIME_LIMIT,
        max_instructions: -1,
        file: None,
        dump: false,
        entry: None,
        uart_input: Vec::new(),
        trace: 0,
        step: false,
        uart_never_ready: false,
        terminal: false,
        echo: false,
        stack_kb: 3,
        load_binaries: Vec::new(),
        patches: Vec::new(),
        base_addr: 0,
        switch_pressed: false,
    };

    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--demo" => cli.command = "demo".to_string(),
            "--run" => {
                cli.command = "run".to_string();
                if i + 1 < args.len() && !args[i + 1].starts_with('-') {
                    cli.file = Some(args[i + 1].clone());
                    i += 1;
                }
            }
            "--assemble" => {
                cli.command = "assemble".to_string();
            }
            "--speed" | "-s" => {
                if i + 1 < args.len() {
                    cli.speed = args[i + 1].parse().unwrap_or(DEFAULT_SPEED);
                    i += 1;
                }
            }
            "--time" | "-t" => {
                if i + 1 < args.len() {
                    cli.time_limit = args[i + 1].parse().unwrap_or(DEFAULT_TIME_LIMIT);
                    i += 1;
                }
            }
            "--dump" => {
                cli.dump = true;
            }
            "--max-instructions" | "-n" => {
                if i + 1 < args.len() {
                    cli.max_instructions = args[i + 1].parse().unwrap_or(-1);
                    i += 1;
                }
            }
            "--uart-input" | "-u" => {
                if i + 1 < args.len() {
                    // Parse escape sequences: \n, \x21, etc.
                    let s = &args[i + 1];
                    let mut bytes = Vec::new();
                    let mut chars = s.chars().peekable();
                    while let Some(ch) = chars.next() {
                        if ch == '\\' {
                            match chars.next() {
                                Some('n') => bytes.push(b'\n'),
                                Some('r') => bytes.push(b'\r'),
                                Some('\\') => bytes.push(b'\\'),
                                Some('x') => {
                                    let hi = chars.next().unwrap_or('0');
                                    let lo = chars.next().unwrap_or('0');
                                    let hex = format!("{}{}", hi, lo);
                                    bytes.push(u8::from_str_radix(&hex, 16).unwrap_or(0));
                                }
                                Some(c) => { bytes.push(b'\\'); bytes.push(c as u8); }
                                None => bytes.push(b'\\'),
                            }
                        } else {
                            bytes.push(ch as u8);
                        }
                    }
                    cli.uart_input = bytes;
                    i += 1;
                }
            }
            "--entry" | "-e" => {
                if i + 1 < args.len() {
                    cli.entry = Some(args[i + 1].clone());
                    i += 1;
                }
            }
            "--trace" => {
                if i + 1 < args.len() {
                    cli.trace = args[i + 1].parse().unwrap_or(50);
                    i += 1;
                } else {
                    cli.trace = 50;
                }
            }
            "--step" => {
                cli.step = true;
            }
            "--switch" => {
                if i + 1 < args.len() {
                    match args[i + 1].to_lowercase().as_str() {
                        "on" | "pressed" | "1" => cli.switch_pressed = true,
                        "off" | "released" | "0" => cli.switch_pressed = false,
                        _ => {
                            eprintln!("Error: --switch must be on or off");
                            std::process::exit(1);
                        }
                    }
                    i += 1;
                }
            }
            "--uart-never-ready" => {
                cli.uart_never_ready = true;
            }
            "--terminal" => {
                cli.terminal = true;
            }
            "--echo" => {
                cli.echo = true;
            }
            "--stack-kilobytes" => {
                if i + 1 < args.len() {
                    match args[i + 1].parse::<u32>() {
                        Ok(3) => cli.stack_kb = 3,
                        Ok(8) => cli.stack_kb = 8,
                        _ => {
                            eprintln!("Error: --stack-kilobytes must be 3 or 8");
                            std::process::exit(1);
                        }
                    }
                    i += 1;
                }
            }
            "--load-binary" => {
                if i + 1 < args.len() {
                    let spec = &args[i + 1];
                    match spec.rsplit_once('@') {
                        Some((file, addr_str)) => {
                            match parse_numeric_addr(addr_str.trim()) {
                                Some(a) => cli.load_binaries.push((file.to_string(), a)),
                                None => {
                                    eprintln!("Error: invalid address in --load-binary '{}' (expected <file>@<addr>)", spec);
                                    std::process::exit(1);
                                }
                            }
                        }
                        None => {
                            eprintln!("Error: --load-binary requires <file>@<addr> format (e.g., hello.p24@0x010000)");
                            std::process::exit(1);
                        }
                    }
                    i += 1;
                }
            }
            "--base-addr" => {
                if i + 1 < args.len() {
                    match parse_numeric_addr(args[i + 1].trim()) {
                        Some(a) => cli.base_addr = a,
                        None => {
                            eprintln!("Error: invalid --base-addr '{}' (expected address, e.g., 0x010000)", args[i + 1]);
                            std::process::exit(1);
                        }
                    }
                    i += 1;
                }
            }
            "--patch" => {
                if i + 1 < args.len() {
                    let spec = &args[i + 1];
                    match spec.split_once('=') {
                        Some((addr_str, val_str)) => {
                            let addr = parse_numeric_addr(addr_str.trim());
                            let val = parse_numeric_addr(val_str.trim());
                            match (addr, val) {
                                (Some(a), Some(v)) => cli.patches.push((a, v)),
                                _ => {
                                    eprintln!("Error: invalid --patch '{}' (expected <addr>=<value>, e.g., 0x09D7=0x010000)", spec);
                                    std::process::exit(1);
                                }
                            }
                        }
                        None => {
                            eprintln!("Error: --patch requires <addr>=<value> format (e.g., 0x09D7=0x010000)");
                            std::process::exit(1);
                        }
                    }
                    i += 1;
                }
            }
            _ => {
                if cli.command.is_empty() && !args[i].starts_with('-') {
                    cli.file = Some(args[i].clone());
                }
            }
        }
        i += 1;
    }

    cli
}


/// Print one row of 16 bytes in hex + ASCII
fn print_hex_row(emu: &EmulatorCore, addr: u32) {
    print!("  {:06X}:", addr);
    for j in 0..16u32 {
        print!(" {:02X}", emu.read_byte(addr + j));
    }
    print!("  |");
    for j in 0..16u32 {
        let b = emu.read_byte(addr + j);
        if (0x20..=0x7E).contains(&b) {
            print!("{}", b as char);
        } else {
            print!(".");
        }
    }
    println!("|");
}

/// Check if a 16-byte row is all zero
fn row_is_zero(emu: &EmulatorCore, addr: u32) -> bool {
    for j in 0..16u32 {
        if emu.read_byte(addr + j) != 0 {
            return false;
        }
    }
    true
}

/// Dump a memory region, collapsing runs of zero rows.
/// Shows non-zero rows verbatim; consecutive zero rows are summarized.
fn dump_memory_region(emu: &EmulatorCore, start: u32, end: u32) {
    let mut addr = start & !0xF; // align to 16
    while addr <= end {
        if row_is_zero(emu, addr) {
            // Count consecutive zero rows
            let zero_start = addr;
            while addr <= end && row_is_zero(emu, addr) {
                addr += 16;
            }
            let zero_bytes = addr - zero_start;
            if zero_bytes <= 16 {
                // Single zero row — just print it
                print_hex_row(emu, zero_start);
            } else {
                println!("  {:06X}..{:06X}: {} bytes all zero", zero_start, addr - 1, zero_bytes);
            }
        } else {
            print_hex_row(emu, addr);
            addr += 16;
        }
    }
}

/// Print I/O state in a human-readable format
fn print_io_state(emu: &EmulatorCore) {
    let snap = emu.snapshot();
    println!("\n=== I/O FF0000-FFFFFF (64 KB, memory-mapped peripherals) ===");

    // LED/Switch at 0xFF0000
    // LED state is internal (written by sb to FF0000), not readable via lb
    // Switch state is what lb from FF0000 returns (active-low: 0=pressed, 1=released)
    let led = snap.led;
    let switch = snap.button;
    print!("  LED D2:  0x{:02X}  ", led);
    if led & 1 == 0 { print!("ON (active-low)"); } else { print!("off"); }
    println!();
    print!("  BTN S2:  0x{:02X}  ", switch);
    println!("{}", if switch & 1 == 0 { "PRESSED (active-low)" } else { "released" });

    // Interrupt enable at 0xFF0010
    let ie = emu.read_byte(0xFF0010);
    println!("  FF0010 IntEn:  0x{:02X}  UART RX IRQ: {}", ie, if ie & 1 == 1 { "enabled" } else { "disabled" });

    // UART
    let uart_stat = emu.read_byte(0xFF0101);
    println!("  FF0100 UART:   status=0x{:02X}  RX ready: {}  CTS: {}  TX busy: {}",
             uart_stat,
             if uart_stat & 1 == 1 { "yes" } else { "no" },
             if uart_stat & 2 == 2 { "yes" } else { "no" },
             if uart_stat & 0x80 == 0x80 { "yes" } else { "no" });

    let uart_out = emu.get_uart_output();
    if !uart_out.is_empty() {
        let escaped: String = uart_out.chars().map(|c| {
            if c == '\n' { "\\n".to_string() }
            else if c == '\r' { "\\r".to_string() }
            else { c.to_string() }
        }).collect();
        println!("  UART TX log:   \"{}\"", escaped);
    }
}

/// Print register and full memory dump
///
/// COR24 24-bit address space:
///   000000-0FFFFF  SRAM (1 MB) — code at low addresses, data/globals above
///   100000-FDFFFF  Unmapped (~14 MB gap, reads 0, writes ignored)
///   FE0000-FEDDFF  Unmapped (below EBR)
///   FEE000-FEFFFF  EBR (8 KB embedded block RAM) — stack (SP init = FEEC00)
///   FF0000-FFFFFF  I/O (64 KB, 4 registers mapped, rest reads 0)
fn print_dump(emu: &EmulatorCore) {
    let snap = emu.snapshot();
    println!("\n=== Registers ===");
    println!("  PC:  0x{:06X}    C: {}", snap.pc, if snap.c { "1" } else { "0" });
    println!("  r0:  0x{:06X}  ({:8})", snap.regs[0], snap.regs[0]);
    println!("  r1:  0x{:06X}  ({:8})", snap.regs[1], snap.regs[1]);
    println!("  r2:  0x{:06X}  ({:8})", snap.regs[2], snap.regs[2]);
    println!("  fp:  0x{:06X}", snap.regs[3]);
    println!("  sp:  0x{:06X}", snap.regs[4]);
    println!("\n=== Emulator ===");
    println!("  Instructions: {}", snap.instructions);
    println!("  Halted: {}", snap.halted);

    // --- Region 1: SRAM (000000-0FFFFF) ---
    let sram = emu.sram();
    let sram_end = sram.iter().rposition(|&b| b != 0)
        .map(|pos| ((pos as u32) | 0xF) + 1)
        .unwrap_or(0);
    println!("\n=== SRAM 000000-0FFFFF (1 MB) ===");
    if sram_end > 0 {
        dump_memory_region(emu, 0x000000, sram_end - 1);
        if sram_end < 0x100000 {
            println!("  {:06X}..0FFFFF: {} bytes all zero",
                     sram_end, 0x100000 - sram_end);
        }
    } else {
        println!("  000000..0FFFFF: 1048576 bytes all zero");
    }

    // --- Region 2: Unmapped gap ---
    println!("\n=== Unmapped 100000-FEDDFF (14.9 MB, not installed) ===");

    // --- Region 3: EBR / Stack (FEE000-FEFFFF) ---
    println!("\n=== EBR FEE000-FEFFFF (8 KB, stack) ===");
    let ebr = emu.ebr();
    if ebr.iter().any(|&b| b != 0) {
        dump_memory_region(emu, 0xFEE000, 0xFEFFFF);
    } else {
        println!("  FEE000..FEFFFF: 8192 bytes all zero");
    }

    // --- Region 4: I/O (FF0000-FFFFFF) ---
    print_io_state(emu);
}

/// Run in step mode: execute one instruction at a time, printing each.
/// Stops on halt, max_instructions limit, or loop detection.
fn run_step_mode(emu: &mut EmulatorCore, max_instructions: i64, uart_input: &[u8]) {
    let mut uart_pos = 0usize;
    let mut prev_uart_len = 0usize;
    let max = if max_instructions < 0 { 10_000 } else { max_instructions as u64 };

    println!("{:>5} {:>8}  {:<24}  {}", "#", "PC", "Instruction", "Changes");
    println!("{}", "-".repeat(80));

    for n in 0..max {
        // Feed UART input when previous byte consumed (FIFO drain)
        if uart_pos < uart_input.len() {
            let uart_status = emu.read_byte(0xFF0101);
            if uart_status & 0x01 == 0 {
                let ch = uart_input[uart_pos];
                emu.send_uart_byte(ch);
                println!("  --- UART RX: 0x{:02X} ('{}') ---",
                    ch, if (0x20..=0x7E).contains(&ch) { ch as char } else { '.' });
                uart_pos += 1;
            }
        }

        let result = emu.step();

        // Print the trace entry for this instruction
        let trace = emu.trace();
        if let Some(entry) = trace.last_n(1).first() {
            println!("{}", entry);
        }

        // Print any new UART output
        let output = emu.get_uart_output();
        if output.len() > prev_uart_len {
            let new = &output[prev_uart_len..];
            for ch in new.chars() {
                if ch == '\n' {
                    println!("  >>> UART TX: '\\n'");
                } else {
                    println!("  >>> UART TX: '{}'  (0x{:02X})", ch, ch as u8);
                }
            }
            prev_uart_len = output.len();
        }

        if result.instructions_run == 0 {
            println!("\n--- Halted after {} instructions ---", n);
            break;
        }
    }

    let uart = emu.get_uart_output();
    if !uart.is_empty() {
        println!("\nUART output: {}", uart);
    }
    println!("\nExecuted {} instructions", emu.instructions_count());
    if emu.is_halted() {
        println!("CPU halted (self-branch detected)");
    }
}

// --- Terminal mode (raw termios) ---

/// RAII guard that restores terminal settings on drop.
struct TermiosGuard {
    fd: libc::c_int,
    original: libc::termios,
}

impl Drop for TermiosGuard {
    fn drop(&mut self) {
        unsafe { libc::tcsetattr(self.fd, libc::TCSAFLUSH, &self.original); }
    }
}

/// Put stdin into raw mode (character-at-a-time, no echo, no signals).
/// Returns a guard that restores the original settings on drop.
fn set_raw_mode() -> Result<TermiosGuard, String> {
    unsafe {
        let fd = libc::STDIN_FILENO;
        let mut original: libc::termios = std::mem::zeroed();
        if libc::tcgetattr(fd, &mut original) != 0 {
            return Err("tcgetattr failed".to_string());
        }
        let mut raw = original;
        raw.c_lflag &= !(libc::ICANON | libc::ECHO | libc::ISIG);
        raw.c_iflag &= !(libc::IXON | libc::ICRNL);
        raw.c_cc[libc::VMIN] = 0;
        raw.c_cc[libc::VTIME] = 0;
        if libc::tcsetattr(fd, libc::TCSAFLUSH, &raw) != 0 {
            return Err("tcsetattr failed".to_string());
        }
        Ok(TermiosGuard { fd, original })
    }
}

/// Run the emulator in terminal mode: stdin→UART RX, UART TX→stdout.
fn run_terminal_mode(emu: &mut EmulatorCore, speed: u64, time_limit: f64, max_instructions: i64, echo: bool) -> u64 {
    let is_tty = unsafe { libc::isatty(libc::STDIN_FILENO) } != 0;

    let _guard = if is_tty {
        match set_raw_mode() {
            Ok(g) => {
                // Also install a panic hook that restores terminal
                let orig = g.original;
                let prev_hook = std::panic::take_hook();
                std::panic::set_hook(Box::new(move |info| {
                    unsafe { libc::tcsetattr(libc::STDIN_FILENO, libc::TCSAFLUSH, &orig); }
                    prev_hook(info);
                }));
                Some(g)
            }
            Err(e) => {
                eprintln!("Warning: could not set raw mode: {}", e);
                None
            }
        }
    } else {
        None
    };

    if is_tty {
        // Use \r\n since we're in raw mode (no output processing)
        eprint!("[cor24-run terminal mode \u{2014} Ctrl-] to exit]\r\n");
    }

    let batch_size: u64 = if speed == 0 { 10_000 } else { (speed / 100).max(100) };
    let batch_duration = if speed == 0 {
        Duration::ZERO
    } else {
        Duration::from_secs_f64(batch_size as f64 / speed as f64)
    };

    let time_limit_duration = if time_limit <= 0.0 {
        Duration::from_secs(3600) // 1 hour default for terminal mode
    } else {
        Duration::from_secs_f64(time_limit)
    };

    let start = Instant::now();
    let mut total_instructions: u64 = 0;
    let mut batch_start = Instant::now();
    let mut prev_uart_len = 0usize;
    let mut stdin_buf: VecDeque<u8> = VecDeque::new();
    let mut read_buf = [0u8; 256];
    let stdin_fd = libc::STDIN_FILENO;
    let mut stdout = std::io::stdout();
    let mut stdin_eof = false;

    emu.resume();

    loop {
        if start.elapsed() >= time_limit_duration {
            break;
        }
        if max_instructions >= 0 && total_instructions >= max_instructions as u64 {
            break;
        }

        let this_batch = if max_instructions >= 0 {
            let remaining = (max_instructions as u64).saturating_sub(total_instructions);
            batch_size.min(remaining).max(1)
        } else {
            batch_size
        };

        let result = emu.run_batch(this_batch);
        total_instructions += result.instructions_run;

        // TX: flush new UART output to stdout as raw bytes
        let output = emu.get_uart_output();
        if output.len() > prev_uart_len {
            let new_bytes = &output.as_bytes()[prev_uart_len..];
            if is_tty {
                // In raw mode, translate \n to \r\n for proper terminal display
                for &b in new_bytes {
                    if b == b'\n' {
                        let _ = stdout.write_all(b"\r\n");
                    } else {
                        let _ = stdout.write_all(&[b]);
                    }
                }
            } else {
                let _ = stdout.write_all(new_bytes);
            }
            let _ = stdout.flush();
            prev_uart_len = output.len();
        }

        // RX: non-blocking read from stdin
        if !stdin_eof {
            let n = unsafe {
                libc::read(stdin_fd, read_buf.as_mut_ptr() as *mut libc::c_void, read_buf.len())
            };
            if n > 0 {
                let mut did_echo = false;
                for &b in &read_buf[..n as usize] {
                    if b == 0x1D {
                        // Ctrl-] — exit
                        if is_tty {
                            eprint!("\r\n[cor24-run exited]\r\n");
                        }
                        return total_instructions;
                    }
                    if stdin_buf.len() < 4096 {
                        stdin_buf.push_back(b);
                    }
                    if echo {
                        match b {
                            b'\r' | b'\n' => { let _ = stdout.write_all(b"\r\n"); }
                            0x08 | 0x7F => { let _ = stdout.write_all(b"\x08 \x08"); }
                            0x20..=0x7E => { let _ = stdout.write_all(&[b]); }
                            _ => {} // don't echo control characters
                        }
                        did_echo = true;
                    }
                }
                if did_echo {
                    let _ = stdout.flush();
                }
            } else if n == 0 && !is_tty {
                // EOF on piped stdin
                stdin_eof = true;
            }
        }

        // Feed buffered input to UART when ready
        if !stdin_buf.is_empty() {
            let status = emu.read_byte(0xFF0101);
            if status & 0x01 == 0 {
                let ch = stdin_buf.pop_front().unwrap();
                emu.send_uart_byte(ch);
            }
        }

        if result.instructions_run == 0 {
            if is_tty {
                eprint!("\r\n[CPU halted]\r\n");
            } else {
                eprintln!("\n[CPU halted]");
            }
            break;
        }

        // Timing synchronization
        if speed > 0 {
            let elapsed = batch_start.elapsed();
            if elapsed < batch_duration {
                thread::sleep(batch_duration - elapsed);
            }
            batch_start = Instant::now();
        }
    }

    if is_tty && start.elapsed() >= time_limit_duration {
        eprint!("\r\n[time limit reached]\r\n");
    }

    total_instructions
}

/// .p24 magic bytes: "P24\0"
const P24_MAGIC: [u8; 4] = [0x50, 0x32, 0x34, 0x00];
const P24_HEADER_SIZE: usize = 18;

/// Load binary files and apply memory patches.
/// Auto-detects .p24 files by magic header and strips the 18-byte header.
fn load_binaries_and_patches(emu: &mut EmulatorCore, binaries: &[(String, u32)], patches: &[(u32, u32)]) {
    for (file_path, addr) in binaries {
        let data = fs::read(file_path).unwrap_or_else(|e| {
            eprintln!("Error: cannot read binary file '{}': {}", file_path, e);
            std::process::exit(1);
        });

        // Auto-detect .p24 header and strip it
        let (body, stripped) = if data.len() >= P24_HEADER_SIZE && data[..4] == P24_MAGIC {
            (&data[P24_HEADER_SIZE..], true)
        } else {
            (data.as_slice(), false)
        };

        for (i, &b) in body.iter().enumerate() {
            emu.write_byte(addr + i as u32, b);
        }
        if stripped {
            println!("Loaded {} bytes from '{}' at 0x{:06X} (stripped {} byte .p24 header)",
                     body.len(), file_path, addr, P24_HEADER_SIZE);
        } else {
            println!("Loaded {} bytes from '{}' at 0x{:06X}", body.len(), file_path, addr);
        }
    }

    // Apply memory patches (24-bit LE values)
    for &(addr, value) in patches {
        emu.write_byte(addr, (value & 0xFF) as u8);
        emu.write_byte(addr + 1, ((value >> 8) & 0xFF) as u8);
        emu.write_byte(addr + 2, ((value >> 16) & 0xFF) as u8);
        println!("Patched 0x{:06X} = 0x{:06X}", addr, value);
    }
}

fn main() {
    let args: Vec<String> = env::args().collect();

    // Handle -h, --help, -V, --version before parsing other args
    if args.len() < 2 || args.contains(&"-h".to_string()) {
        print_short_help();
        return;
    }
    if args.contains(&"--help".to_string()) {
        print_long_help();
        return;
    }
    if args.contains(&"-V".to_string()) || args.contains(&"--version".to_string()) {
        print_version();
        return;
    }

    let mut cli = parse_args();

    // Binary-only mode: --load-binary without --run
    if cli.command.is_empty() && !cli.load_binaries.is_empty() {
        cli.command = "binary".to_string();
    }

    match cli.command.as_str() {
        "demo" => {
            println!("=== COR24 LED Demo ===\n");
            println!("Binary counter 0-255 on LEDs with spin loop delay");
            println!("Speed: {} instructions/sec, Time limit: {}s\n", cli.speed, cli.time_limit);

            let mut asm = Assembler::new();
            let result = asm.assemble(DEMO_SOURCE);
            if !result.errors.is_empty() {
                eprintln!("Assembly error: {}", result.errors.join("\n"));
                return;
            }

            println!("Program listing:");
            for line in &result.lines {
                if !line.bytes.is_empty() {
                    let bytes: String = line.bytes.iter().map(|b| format!("{:02X} ", b)).collect();
                    println!("{:04X}: {:14} {}", line.address, bytes.trim(), line.source);
                }
            }
            println!();

            let mut emu = EmulatorCore::new();
            load_assembled(&mut emu, &result);

            println!("Running (Ctrl+C to stop)...\n");
            let instructions = run_with_timing(&mut emu, cli.speed, cli.time_limit, cli.max_instructions, &cli.uart_input);

            println!("\n\nExecuted {} instructions in {:.1}s", instructions, cli.time_limit);
            println!("Effective speed: {:.0} IPS", instructions as f64 / cli.time_limit);
            if cli.dump { print_dump(&emu); }
        }

        "run" => {
            let filename = match cli.file {
                Some(f) => f,
                None => {
                    eprintln!("Usage: cor24-run --run <file.s>");
                    return;
                }
            };

            let source = fs::read_to_string(&filename).expect("Cannot read file");
            let mut asm = Assembler::new();
            let result = asm.assemble(&source);
            if !result.errors.is_empty() {
                eprintln!("Assembly errors:");
                for err in &result.errors {
                    eprintln!("  {}", err);
                }
                return;
            }

            let byte_count: usize = result.lines.iter().map(|l| l.bytes.len()).sum();
            println!("Assembled {} bytes", byte_count);

            let mut emu = EmulatorCore::new();
            if cli.uart_never_ready {
                emu.set_uart_never_ready(true);
            }
            if cli.switch_pressed {
                emu.set_button_pressed(true);
            }
            // Set stack size: 3 KB → SP=0xFEEC00 (default), 8 KB → SP=0xFF0000
            if cli.stack_kb == 8 {
                emu.set_reg(4, 0xFF0000); // SP = top of full EBR window
            }
            load_assembled(&mut emu, &result);

            load_binaries_and_patches(&mut emu, &cli.load_binaries, &cli.patches);

            if let Some(entry_str) = &cli.entry {
                // Try numeric address first, then label lookup
                if let Some(addr) = parse_numeric_addr(entry_str) {
                    emu.set_pc(addr);
                    println!("Entry point: 0x{:06X}", addr);
                } else {
                    // Find label address in assembly result
                    let mut found = false;
                    for line in &result.lines {
                        let src = line.source.trim();
                        if src.ends_with(':') && src.trim_end_matches(':') == entry_str.as_str() {
                            emu.set_pc(line.address);
                            println!("Entry point: {} @ 0x{:06X}", entry_str, line.address);
                            found = true;
                            break;
                        }
                    }
                    if !found {
                        eprintln!("Warning: entry point '{}' not found, starting at 0x000000", entry_str);
                    }
                }
            }

            if cli.echo && !cli.terminal {
                eprintln!("Error: --echo requires --terminal");
                return;
            }

            if cli.terminal {
                // Validate incompatible flags
                if !cli.uart_input.is_empty() {
                    eprintln!("Error: --terminal and --uart-input are incompatible");
                    return;
                }
                if cli.step {
                    eprintln!("Error: --terminal and --step are incompatible");
                    return;
                }

                let speed = if cli.speed == DEFAULT_SPEED { 0 } else { cli.speed };
                let time_limit = if cli.time_limit == DEFAULT_TIME_LIMIT { 0.0 } else { cli.time_limit };

                let instructions = run_terminal_mode(&mut emu, speed, time_limit, cli.max_instructions, cli.echo);

                eprintln!("Executed {} instructions", instructions);
                if cli.trace > 0 {
                    print!("{}", emu.trace().format_last(cli.trace));
                }
                if cli.dump { print_dump(&emu); }
                return;
            }

            println!("Running (speed: {} IPS, time limit: {}s)...\n",
                     if cli.speed == 0 { "max".to_string() } else { cli.speed.to_string() },
                     cli.time_limit);

            if cli.step {
                // Step mode: execute one instruction at a time, printing each
                run_step_mode(&mut emu, cli.max_instructions, &cli.uart_input);
            } else {
                let instructions = run_with_timing(&mut emu, cli.speed, cli.time_limit, cli.max_instructions, &cli.uart_input);

                // Print UART output if any
                let uart = emu.get_uart_output();
                if !uart.is_empty() {
                    println!("\nUART output: {}", uart);
                }

                println!("\nExecuted {} instructions", instructions);
                if emu.is_halted() {
                    println!("CPU halted (self-branch detected)");
                }
            }
            if cli.trace > 0 {
                print!("{}", emu.trace().format_last(cli.trace));
            }
            if cli.dump { print_dump(&emu); }
        }

        "assemble" => {
            if args.len() < 5 {
                eprintln!("Usage: cor24-run --assemble <in.s> <out.bin> <out.lst>");
                return;
            }
            let source = fs::read_to_string(&args[2]).expect("Cannot read file");
            let mut asm = Assembler::new();
            let result = asm.assemble_at(&source, cli.base_addr);
            if !result.errors.is_empty() {
                eprintln!("Assembly error: {}", result.errors.join("\n"));
                return;
            }

            let machine_code: Vec<u8> = result.lines.iter()
                .flat_map(|line| line.bytes.iter().copied())
                .collect();

            fs::write(&args[3], &machine_code).expect("Cannot write .bin");
            let mut lst_file = fs::File::create(&args[4]).expect("Cannot write .lst");
            for line in &result.lines {
                if !line.bytes.is_empty() {
                    let bytes: String = line.bytes.iter().map(|b| format!("{:02X} ", b)).collect();
                    writeln!(lst_file, "{:04X}: {:14} {}", line.address, bytes.trim(), line.source).ok();
                } else if !line.source.is_empty() {
                    writeln!(lst_file, "                    {}", line.source).ok();
                }
            }
            if cli.base_addr != 0 {
                println!("Assembled {} bytes at base 0x{:06X} to {}", machine_code.len(), cli.base_addr, args[3]);
            } else {
                println!("Assembled {} bytes to {}", machine_code.len(), args[3]);
            }
            println!("Wrote listing to {}", args[4]);
        }

        "binary" => {
            // Binary-only mode: load pre-assembled binaries, no assembly step
            let mut emu = EmulatorCore::new();
            if cli.uart_never_ready {
                emu.set_uart_never_ready(true);
            }
            if cli.switch_pressed {
                emu.set_button_pressed(true);
            }
            if cli.stack_kb == 8 {
                emu.set_reg(4, 0xFF0000);
            }

            load_binaries_and_patches(&mut emu, &cli.load_binaries, &cli.patches);

            // --entry is required in binary mode and must be numeric
            if let Some(entry_str) = &cli.entry {
                match parse_numeric_addr(entry_str) {
                    Some(addr) => {
                        emu.set_pc(addr);
                        println!("Entry point: 0x{:06X}", addr);
                    }
                    None => {
                        eprintln!("Error: --entry must be a numeric address in binary mode (e.g., 0x000000)");
                        std::process::exit(1);
                    }
                }
            } else {
                // Default to 0 if not specified
                println!("Entry point: 0x000000 (default)");
            }

            if cli.echo && !cli.terminal {
                eprintln!("Error: --echo requires --terminal");
                return;
            }

            if cli.terminal {
                if !cli.uart_input.is_empty() {
                    eprintln!("Error: --terminal and --uart-input are incompatible");
                    return;
                }
                if cli.step {
                    eprintln!("Error: --terminal and --step are incompatible");
                    return;
                }

                let speed = if cli.speed == DEFAULT_SPEED { 0 } else { cli.speed };
                let time_limit = if cli.time_limit == DEFAULT_TIME_LIMIT { 0.0 } else { cli.time_limit };

                let instructions = run_terminal_mode(&mut emu, speed, time_limit, cli.max_instructions, cli.echo);

                eprintln!("Executed {} instructions", instructions);
                if cli.trace > 0 {
                    print!("{}", emu.trace().format_last(cli.trace));
                }
                if cli.dump { print_dump(&emu); }
                return;
            }

            println!("Running (speed: {} IPS, time limit: {}s)...\n",
                     if cli.speed == 0 { "max".to_string() } else { cli.speed.to_string() },
                     cli.time_limit);

            if cli.step {
                run_step_mode(&mut emu, cli.max_instructions, &cli.uart_input);
            } else {
                let instructions = run_with_timing(&mut emu, cli.speed, cli.time_limit, cli.max_instructions, &cli.uart_input);

                let uart = emu.get_uart_output();
                if !uart.is_empty() {
                    println!("\nUART output: {}", uart);
                }

                println!("\nExecuted {} instructions", instructions);
                if emu.is_halted() {
                    println!("CPU halted (self-branch detected)");
                }
            }
            if cli.trace > 0 {
                print!("{}", emu.trace().format_last(cli.trace));
            }
            if cli.dump { print_dump(&emu); }
        }

        _ => {
            eprintln!("Unknown command. Use --demo, --run, --load-binary, or --assemble");
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    // --- parse_numeric_addr ---

    #[test]
    fn test_parse_hex_prefix() {
        assert_eq!(parse_numeric_addr("0x010000"), Some(0x010000));
        assert_eq!(parse_numeric_addr("0X0"), Some(0));
        assert_eq!(parse_numeric_addr("0xFF"), Some(0xFF));
    }

    #[test]
    fn test_parse_hex_suffix() {
        assert_eq!(parse_numeric_addr("010000h"), Some(0x010000));
        assert_eq!(parse_numeric_addr("FFH"), Some(0xFF));
    }

    #[test]
    fn test_parse_decimal() {
        assert_eq!(parse_numeric_addr("0"), Some(0));
        assert_eq!(parse_numeric_addr("65536"), Some(65536));
    }

    #[test]
    fn test_parse_invalid() {
        assert_eq!(parse_numeric_addr("xyz"), None);
        assert_eq!(parse_numeric_addr(""), None);
    }

    // --- .p24 header detection ---

    #[test]
    fn test_p24_magic_detection() {
        // Valid .p24: magic + 14 header bytes + 5 body bytes
        let mut data = vec![0x50, 0x32, 0x34, 0x00]; // "P24\0"
        data.extend_from_slice(&[0; 14]); // rest of header
        data.extend_from_slice(b"HELLO");
        assert_eq!(data.len(), 23);
        assert!(data.len() >= P24_HEADER_SIZE && data[..4] == P24_MAGIC);
        let body = &data[P24_HEADER_SIZE..];
        assert_eq!(body, b"HELLO");
    }

    #[test]
    fn test_raw_binary_no_strip() {
        let data = vec![0x44, 0x05, 0x5A]; // lc r0,5; mov r1,r0
        assert!(!(data.len() >= P24_HEADER_SIZE && data[..4] == P24_MAGIC));
    }

    // --- load_binaries_and_patches ---

    #[test]
    fn test_patch_writes_24bit_le() {
        let mut emu = EmulatorCore::new();
        load_binaries_and_patches(&mut emu, &[], &[(0x100, 0x010000)]);
        assert_eq!(emu.read_byte(0x100), 0x00);
        assert_eq!(emu.read_byte(0x101), 0x00);
        assert_eq!(emu.read_byte(0x102), 0x01);
    }

    #[test]
    fn test_patch_multiple() {
        let mut emu = EmulatorCore::new();
        load_binaries_and_patches(&mut emu, &[], &[(0x100, 0xABCDEF), (0x200, 0x42)]);
        assert_eq!(emu.read_byte(0x100), 0xEF);
        assert_eq!(emu.read_byte(0x101), 0xCD);
        assert_eq!(emu.read_byte(0x102), 0xAB);
        assert_eq!(emu.read_byte(0x200), 0x42);
        assert_eq!(emu.read_byte(0x201), 0x00);
        assert_eq!(emu.read_byte(0x202), 0x00);
    }

    #[test]
    fn test_load_raw_binary_file() {
        let tmp = std::env::temp_dir().join("cor24_test_raw.bin");
        fs::write(&tmp, &[0x44, 0x05, 0x5A]).unwrap();
        let mut emu = EmulatorCore::new();
        load_binaries_and_patches(
            &mut emu,
            &[(tmp.to_string_lossy().to_string(), 0x1000)],
            &[],
        );
        assert_eq!(emu.read_byte(0x1000), 0x44);
        assert_eq!(emu.read_byte(0x1001), 0x05);
        assert_eq!(emu.read_byte(0x1002), 0x5A);
        fs::remove_file(&tmp).ok();
    }

    #[test]
    fn test_load_p24_strips_header() {
        let tmp = std::env::temp_dir().join("cor24_test.p24");
        let mut data = vec![0x50, 0x32, 0x34, 0x00]; // P24 magic (4 bytes)
        data.extend_from_slice(&[0x01]);               // version (1 byte)
        data.extend_from_slice(&[0x00, 0x00, 0x00]);   // entry_point (3 bytes)
        data.extend_from_slice(&[0x03, 0x00, 0x00]);   // code_size (3 bytes)
        data.extend_from_slice(&[0x00, 0x00, 0x00]);   // data_size (3 bytes)
        data.extend_from_slice(&[0x00, 0x00, 0x00]);   // global_count (3 bytes)
        data.push(0x00);                                // reserved (1 byte)
        data.extend_from_slice(&[0xAA, 0xBB, 0xCC]);   // body (3 bytes)
        assert_eq!(data.len(), P24_HEADER_SIZE + 3);    // 18 + 3 = 21
        fs::write(&tmp, &data).unwrap();

        let mut emu = EmulatorCore::new();
        load_binaries_and_patches(
            &mut emu,
            &[(tmp.to_string_lossy().to_string(), 0x010000)],
            &[],
        );
        // Should load body only, not header
        assert_eq!(emu.read_byte(0x010000), 0xAA);
        assert_eq!(emu.read_byte(0x010001), 0xBB);
        assert_eq!(emu.read_byte(0x010002), 0xCC);
        fs::remove_file(&tmp).ok();
    }

    #[test]
    fn test_binary_mode_runs_program() {
        // Assemble a tiny program: lc r0,42; halt (self-branch)
        let mut asm = Assembler::new();
        let result = asm.assemble("lc r0, 42\nhalt:\n bra halt");
        assert!(result.errors.is_empty(), "errors: {:?}", result.errors);
        let bytes: Vec<u8> = result.lines.iter()
            .flat_map(|l| l.bytes.iter().copied())
            .collect();

        // Load as raw binary and run
        let mut emu = EmulatorCore::new();
        for (i, &b) in bytes.iter().enumerate() {
            emu.write_byte(i as u32, b);
        }
        emu.set_pc(0);
        emu.resume();
        emu.run_batch(100);
        let snap = emu.snapshot();
        assert_eq!(snap.regs[0], 42);
        assert!(snap.halted);
    }

    #[test]
    fn test_assemble_at_base_and_load() {
        // Assemble at 0x010000, load at 0x010000, verify la resolves correctly
        let mut asm = Assembler::new();
        let code = "la r0, target\ntarget:\n  lc r1, 99\nhalt:\n  bra halt";
        let result = asm.assemble_at(code, 0x010000);
        assert!(result.errors.is_empty(), "errors: {:?}", result.errors);

        // target should be at 0x010004 (la is 4 bytes)
        assert_eq!(result.labels["target"], 0x010004);

        // Load at 0x010000 and run
        let mut emu = EmulatorCore::new();
        for (i, &b) in result.bytes.iter().enumerate() {
            emu.write_byte(0x010000 + i as u32, b);
        }
        emu.set_pc(0x010000);
        emu.resume();
        emu.run_batch(100);
        let snap = emu.snapshot();
        // la r0, target should have loaded 0x010004 into r0
        assert_eq!(snap.regs[0], 0x010004);
        assert_eq!(snap.regs[1], 99);
        assert!(snap.halted);
    }
}

//! msp430-to-cor24 CLI
//!
//! Translates MSP430 assembly (from rustc) to COR24 assembly.
//!
//! Usage:
//!   msp430-to-cor24 <input.s> [-o output.s]
//!   msp430-to-cor24 --test           # translate built-in test case
//!   msp430-to-cor24 --compile <dir>  # compile Rust project, translate, assemble

use anyhow::Result;
use std::env;
use std::fs;

fn main() -> Result<()> {
    let args: Vec<String> = env::args().collect();

    // Parse named flags from anywhere in args
    let mut entry_point: Option<String> = None;
    let mut output_path: Option<String> = None;
    let mut positional: Vec<String> = Vec::new();

    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--entry" | "-e" => {
                i += 1;
                entry_point = args.get(i).cloned();
            }
            "-o" => {
                i += 1;
                output_path = args.get(i).cloned();
            }
            _ => positional.push(args[i].clone()),
        }
        i += 1;
    }

    let cmd = positional.first().map(|s| s.as_str()).unwrap_or("");

    match cmd {
        "--test" => run_test(),
        "--compile" => {
            let dir = positional.get(1).map(|s| s.as_str()).unwrap_or(".");
            compile_and_translate(dir, entry_point.as_deref().unwrap_or("start"))
        }
        "" => {
            eprintln!("Usage: msp430-to-cor24 <input.s> [-o output.s] [--entry <func>]");
            eprintln!("       msp430-to-cor24 --test");
            eprintln!("       msp430-to-cor24 --compile <rust-project-dir> [--entry <func>]");
            std::process::exit(1);
        }
        input_path => {
            let msp430_asm = fs::read_to_string(input_path)?;
            let entry = entry_point.as_deref().unwrap_or("start");
            let cor24_asm = wasm2cor24::translate_msp430(&msp430_asm, entry)?;

            if let Some(out_path) = output_path {
                fs::write(&out_path, &cor24_asm)?;
                eprintln!("Wrote COR24 assembly to {}", out_path);
            } else {
                println!("{}", cor24_asm);
            }

            Ok(())
        }
    }
}

fn run_test() -> Result<()> {
    // The MSP430 assembly from our test compilation
    let msp430_asm = r#"
	.file	"msp430_test.93892fd9a69df810-cgu.0"
	.section	.text.add,"ax",@progbits
	.globl	add
	.p2align	1
	.type	add,@function
add:
	add	r13, r12
	ret
.Lfunc_end1:
	.size	add, .Lfunc_end1-add

	.section	.text.bitmask,"ax",@progbits
	.globl	bitmask
	.p2align	1
	.type	bitmask,@function
bitmask:
	and	r13, r12
	ret
.Lfunc_end2:
	.size	bitmask, .Lfunc_end2-bitmask

	.section	.text.delay,"ax",@progbits
	.globl	delay
	.p2align	1
	.type	delay,@function
delay:
	sub	#2, r1
	tst	r12
	jeq	.LBB5_3
	add	#-1, r12
.LBB5_2:
	mov	r12, 0(r1)
	add	#-1, r12
	cmp	#-1, r12
	jne	.LBB5_2
.LBB5_3:
	add	#2, r1
	ret
.Lfunc_end5:
	.size	delay, .Lfunc_end5-delay

	.section	.text.mmio_read,"ax",@progbits
	.globl	mmio_read
	.p2align	1
	.type	mmio_read,@function
mmio_read:
	mov	0(r12), r12
	ret
.Lfunc_end6:
	.size	mmio_read, .Lfunc_end6-mmio_read

	.section	.text.mmio_write,"ax",@progbits
	.globl	mmio_write
	.p2align	1
	.type	mmio_write,@function
mmio_write:
	mov	r13, 0(r12)
	ret
.Lfunc_end7:
	.size	mmio_write, .Lfunc_end7-mmio_write

	.section	.text.blink_loop,"ax",@progbits
	.globl	blink_loop
	.p2align	1
	.type	blink_loop,@function
blink_loop:
.LBB2_1:
	mov	#-256, r12
	mov	#1, r13
	call	#mmio_write
	mov	#1000, r12
	call	#delay
	mov	#-256, r12
	clr	r13
	call	#mmio_write
	mov	#1000, r12
	call	#delay
	jmp	.LBB2_1
.Lfunc_end2b:
	.size	blink_loop, .Lfunc_end2b-blink_loop

	.section	.text.button_echo,"ax",@progbits
	.globl	button_echo
	.p2align	1
	.type	button_echo,@function
button_echo:
.LBB3_1:
	mov	#-256, r12
	call	#mmio_read
	mov	r12, r13
	and	#1, r13
	mov	#-256, r12
	call	#mmio_write
	jmp	.LBB3_1
.Lfunc_end3:
	.size	button_echo, .Lfunc_end3-button_echo

	.section	.text.compare_branch,"ax",@progbits
	.globl	compare_branch
	.p2align	1
	.type	compare_branch,@function
compare_branch:
	cmp	r13, r12
	jlo	.LBB4_2
	mov	r13, r12
.LBB4_2:
	ret
.Lfunc_end4:
	.size	compare_branch, .Lfunc_end4-compare_branch

	.section	.text.add_three,"ax",@progbits
	.globl	add_three
	.p2align	1
	.type	add_three,@function
add_three:
	add	r13, r12
	add	r14, r12
	ret
.Lfunc_end1b:
	.size	add_three, .Lfunc_end1b-add_three

	.section	.text.shift_and_mask,"ax",@progbits
	.globl	shift_and_mask
	.p2align	1
	.type	shift_and_mask,@function
shift_and_mask:
	and.b	#15, r13
	cmp.b	#0, r13
	jeq	.LBB8_2
.LBB8_1:
	clrc
	rrc	r12
	sub.b	#1, r13
	jne	.LBB8_1
.LBB8_2:
	and	#15, r12
	ret
.Lfunc_end8:
	.size	shift_and_mask, .Lfunc_end8-shift_and_mask

	.section	.text.start,"ax",@progbits
	.globl	start
	.p2align	1
	.type	start,@function
start:
	call	#blink_loop
.Lfunc_end9:
	.size	start, .Lfunc_end9-start
"#;

    let cor24_asm = wasm2cor24::translate_msp430(msp430_asm, "start")?;

    println!("=== MSP430 -> COR24 Translation ===\n");
    println!("{}", cor24_asm);

    // Also try assembling it to verify syntax
    println!("\n=== Verifying assembly... ===\n");
    let mut assembler = cor24_emulator::assembler::Assembler::new();
    let result = assembler.assemble(&cor24_asm);
    if result.errors.is_empty() {
        println!("Assembly successful! {} bytes generated.", result.bytes.len());
        for line in &result.lines {
            if !line.source.trim().is_empty() {
                println!("  {:06X}: {:16} {}", line.address,
                    line.bytes.iter().map(|b| format!("{:02X}", b)).collect::<Vec<_>>().join(" "),
                    line.source);
            }
        }
    } else {
        println!("Assembly errors:");
        for err in &result.errors {
            println!("  ERROR: {}", err);
        }
    }

    Ok(())
}

/// Compile a Rust project to MSP430 assembly, then translate to COR24
fn compile_and_translate(dir: &str, entry_point: &str) -> Result<()> {
    use std::process::Command;

    eprintln!("Compiling {} to MSP430 assembly...", dir);

    let output = Command::new("rustup")
        .args(["run", "nightly", "cargo", "rustc",
               "--target", "msp430-none-elf",
               "-Z", "build-std=core",
               "--release",
               "--", "--emit", "asm"])
        .current_dir(dir)
        .output()?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        anyhow::bail!("Compilation failed:\n{}", stderr);
    }

    // Find the generated .s file
    let target_dir = format!("{}/target/msp430-none-elf/release/deps", dir);
    let mut asm_file = None;
    for entry in fs::read_dir(&target_dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.extension().map(|e| e == "s").unwrap_or(false) {
            asm_file = Some(path);
            break;
        }
    }

    let asm_path = asm_file.ok_or_else(|| anyhow::anyhow!("No .s file found in {}", target_dir))?;
    eprintln!("Found MSP430 assembly: {}", asm_path.display());

    let msp430_asm = fs::read_to_string(&asm_path)?;
    let cor24_asm = wasm2cor24::translate_msp430(&msp430_asm, entry_point)?;


    println!("{}", cor24_asm);

    Ok(())
}

