15	/// Translate WASM binary to COR24 assembly
16	pub fn translate_wasm(wasm: &[u8]) -> Result<String> {
17	    let mut output = String::new();
18	    output.push_str("; COR24 Assembly - Generated by wasm2cor24\n");
19	    output.push_str("; From Rust source via WASM\n\n");
20	
