76	fn translate_function(
77	    name: &str,
78	    func_type: Option<&FuncType>,
79	    body: wasmparser::FunctionBody,
80	) -> Result<String> {
81	    let mut output = String::new();
82	
83	    // Function header
84	    output.push_str(&format!("; Function: {}\n", name));
85	    if let Some(ft) = func_type {
86	        output.push_str(&format!(
87	            "; Signature: ({}) -> {}\n",
88	            ft.params()
89	                .iter()
90	                .map(|t| format!("{:?}", t))
91	                .collect::<Vec<_>>()
92	                .join(", "),
93	            if ft.results().is_empty() {
94	                "void".to_string()
95	            } else {
96	                ft.results()
97	                    .iter()
98	                    .map(|t| format!("{:?}", t))
99	                    .collect::<Vec<_>>()
100	                    .join(", ")
101	            }
102	        ));
103	    }
104	    output.push_str(&format!("{}:\n", name));
105	
106	    // Parse locals
107	    let mut locals_reader = body.get_locals_reader()?;
108	    let mut num_locals: u32 = 0;
109	
110	    for _ in 0..locals_reader.get_count() {
111	        let (count, _ty) = locals_reader.read()?;
112	        num_locals += count;
113	    }
114	
115	    // Get parameter count from function type
116	    let num_params = func_type.map(|ft| ft.params().len() as u32).unwrap_or(0);
117	    let total_locals = num_params + num_locals;
118	
119	    // Always use prologue for stack-based locals (avoids register conflicts)
120	    output.push_str("        push    fp\n");
121	    output.push_str("        mov     fp, sp\n");
122	    if total_locals > 0 {
123	        output.push_str(&format!("        add     sp, -{}\n", total_locals * 3));
124	        // Copy parameters from registers to stack frame
125	        for i in 0..num_params {
126	            let offset = i * 3;
127	            output.push_str(&format!("        sw      r{}, {}(fp)\n", i, offset));
128	        }
129	    }
130	
131	    // Track state
132	    let mut stack_depth: i32 = 0;
133	    let mut code = Vec::new();
134	    let mut label_counter = 0;
135	    let mut block_stack: Vec<(String, String)> = Vec::new();
136	
137	    // Parse operators
138	    let ops_reader = body.get_operators_reader()?;
139	    for op in ops_reader {
140	        let op = op?;
141	        match op {
142	            Operator::LocalGet { local_index } => {
143	                let offset = local_index * 3;
144	                code.push(format!("        lw      r{}, {}(fp)\n", stack_depth, offset));
145	                stack_depth += 1;
146	            }
147	
148	            Operator::LocalSet { local_index } => {
149	                stack_depth -= 1;
150	                let offset = local_index * 3;
151	                code.push(format!("        sw      r{}, {}(fp)\n", stack_depth, offset));
152	            }
153	
154	            Operator::I32Const { value } => {
155	                if (-128..=127).contains(&value) {
156	                    code.push(format!("        lc      r{}, {}\n", stack_depth, value));
157	                } else {
158	                    code.push(format!("        la      r{}, 0x{:06X}\n", stack_depth, value as u32 & 0xFFFFFF));
159	                }
160	                stack_depth += 1;
161	            }
162	
163	            Operator::I32Add => {
164	                stack_depth -= 1;
165	                code.push(format!("        add     r{}, r{}\n", stack_depth - 1, stack_depth));
166	            }
167	
168	            Operator::I32Sub => {
169	                stack_depth -= 1;
170	                code.push(format!("        sub     r{}, r{}\n", stack_depth - 1, stack_depth));
171	            }
172	
173	            Operator::I32And => {
174	                stack_depth -= 1;
175	                code.push(format!("        and     r{}, r{}\n", stack_depth - 1, stack_depth));
176	            }
177	
178	            Operator::I32Or => {
179	                stack_depth -= 1;
180	                code.push(format!("        or      r{}, r{}\n", stack_depth - 1, stack_depth));
181	            }
182	
183	            Operator::I32Store8 { memarg } => {
184	                stack_depth -= 2;
185	                let addr_reg = stack_depth;
186	                let val_reg = stack_depth + 1;
187	                if memarg.offset > 0 {
188	                    code.push(format!("        la      r{}, 0x{:06X}\n", val_reg + 1, memarg.offset as u32 & 0xFFFFFF));
189	                    code.push(format!("        add     r{}, r{}\n", addr_reg, val_reg + 1));
190	                }
191	                code.push(format!("        sb      r{}, 0(r{})\n", val_reg, addr_reg));
192	            }
193	
194	            Operator::Loop { .. } => {
195	                let start = format!(".L{}", label_counter);
196	                let end = format!(".L{}", label_counter + 1);
197	                label_counter += 2;
198	                block_stack.push((start.clone(), end));
199	                code.push(format!("{}:\n", start));
200	            }
201	
202	            Operator::Block { .. } => {
203	                let start = format!(".L{}", label_counter);
204	                let end = format!(".L{}", label_counter + 1);
205	                label_counter += 2;
206	                block_stack.push((start, end));
207	            }
208	
209	            Operator::BrIf { relative_depth } => {
210	                stack_depth -= 1;
211	                if let Some((start, _)) = block_stack.iter().rev().nth(relative_depth as usize) {
212	                    code.push(format!("        ceq     r{}, z\n", stack_depth));
213	                    code.push(format!("        brf     {}\n", start));
214	                }
215	            }
216	
217	            Operator::Br { relative_depth } => {
218	                if let Some((start, _)) = block_stack.iter().rev().nth(relative_depth as usize) {
219	                    code.push(format!("        bra     {}\n", start));
220	                }
221	            }
222	
223	            Operator::I32LtU => {
224	                stack_depth -= 1;
225	                code.push(format!("        clu     r{}, r{}\n", stack_depth - 1, stack_depth));
226	                code.push(format!("        mov     r{}, c\n", stack_depth - 1));
227	            }
228	
229	            Operator::I32Eqz => {
230	                code.push(format!("        ceq     r{}, z\n", stack_depth - 1));
231	                code.push(format!("        mov     r{}, c\n", stack_depth - 1));
232	            }
233	
234	            Operator::End => {
235	                if let Some((_, end)) = block_stack.pop() {
236	                    code.push(format!("{}:\n", end));
237	                }
238	            }
239	
240	            Operator::Return => {
241	                code.push("        mov     sp, fp\n".to_string());
242	                code.push("        pop     fp\n".to_string());
243	                code.push("        jmp     (r1)\n".to_string());
244	            }
245	
246	            Operator::Drop => {
247	                stack_depth -= 1;
248	            }
249	
250	            other => {
251	                code.push(format!("        ; TODO: {:?}\n", other));
252	            }
253	        }
254	    }
255	
256	    for line in code {
257	        output.push_str(&line);
258	    }
259	
260	    // Epilogue
261	    output.push_str("        mov     sp, fp\n");
262	    output.push_str("        pop     fp\n");
263	    output.push_str("        halt\n\n");
264	
265	    Ok(output)
266	}
