    #[test]
    fn test_simple_add() {
        let msp430 = r#"
	.section	.text.add,"ax",@progbits
	.globl	add
	.p2align	1
add:
	add	r13, r12
	ret
"#;
        let result = translate_msp430(msp430, "add").unwrap();
        // r13 is spilled: load spill_13 into r2 (working reg, avoids r0=dst), add, store back
        assert!(
            result.contains("push    r2"),
            "should push working reg. Got:\n{}",
            result
        );
        assert!(
            result.contains("lw      r2, 24(fp)"),
            "should load spill_13. Got:\n{}",
            result
        );
        assert!(
            result.contains("add     r0, r2"),
            "add r0 (r12), r2 (spill_13). Got:\n{}",
            result
        );
        // ret = jmp (r1) — r1 holds return address from jal
        assert!(result.contains("jmp     (r1)"));
    }

