        let msp430 = r#"
	.section	.text.fibonacci,"ax",@progbits
fibonacci:
	cmp	#2, r12
	jhs	.LBB8_2
	mov	r12, r13
	jmp	.LBB8_4
.LBB8_2:
	mov	#2, r14
	clr	r15
	mov	#1, r13
.LBB8_3:
	mov	r13, r11
	mov	r15, r13
	add	r11, r13
	inc	r14
	cmp	r14, r12
	mov	r11, r15
	jhs	.LBB8_3
.LBB8_4:
	mov	r13, r12
	ret
"#;
        let result = translate_msp430(msp430, "start").unwrap();
        // r15 -> spill_15 (offset 27), r11 -> spill_11 (offset 21), r13 -> spill_13 (offset 24)
        // mov r13, r11: both spilled, use r0 as intermediary
        assert!(
            result.contains("lw      r0, 24(fp)"),
            "should load spill_13. Got:\n{}",
            result
        );
        assert!(
            result.contains("sw      r0, 21(fp)"),
            "should store to spill_11. Got:\n{}",
            result
        );
        // mov r15, r13: both spilled
        assert!(
            result.contains("lw      r0, 27(fp)"),
            "should load spill_15. Got:\n{}",
            result
        );
        assert!(
            result.contains("sw      r0, 24(fp)"),
            "should store to spill_13. Got:\n{}",
            result
        );
        // ret = jmp (r1)
        assert!(
            result.contains("jmp     (r1)"),
            "ret should use jmp (r1). Got:\n{}",
            result
        );
    }

