        // Working register must NOT be r0 (would clobber live r12 value)
        // Must NOT be r1 (reserved for return address)
        // So must use r2
        let msp430 = r#"
	.section	.text.test,"ax",@progbits
test:
	add	r12, r10
	ret
"#;
        let result = translate_msp430(msp430, "start").unwrap();
        // Should push r2 (working reg), load spill, operate, store, pop r2
        assert!(
            result.contains("push    r2"),
            "should push working reg r2. Got:\n{}",
            result
        );
        assert!(
            result.contains("lw      r2, 18(fp)"),
            "spill should load into r2. Got:\n{}",
            result
        );
        assert!(
            result.contains("add     r2, r0"),
            "add should use r2 (spill) and r0 (r12). Got:\n{}",
            result
        );
        assert!(
            result.contains("sw      r2, 18(fp)"),
            "result should be stored back. Got:\n{}",
            result
