	mov	#-255, r12
	call	#mmio_write
	ret
"#;
        let result = translate_msp430(msp430, "uart_putc").unwrap();
        // Should be a tail call: la + jmp, no push/pop
        assert!(
            result.contains("; tail call mmio_write"),
            "Should have tail call comment. Got:\n{}",
            result
        );
        assert!(
            result.contains("la      r2, mmio_write"),
