    #[test]
    fn test_spill_countdown() {
        // MSP430 demo_countdown uses r10 (callee-saved, spilled in COR24)
        let msp430 = r#"
	.section	.text.demo_countdown,"ax",@progbits
demo_countdown:
	push	r10
	mov	#10, r10
.LBB5_1:
	mov	#-256, r12
	mov	r10, r13
	call	#mmio_write
	mov	#1000, r12
